const App = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    checkAuthStatus();
  }, []);

  const checkAuthStatus = async () => {
    try {
      const authFlag = await AsyncStorage.getItem(AUTH_KEY);

      if (authFlag === 'true') {
        // User was previously authenticated
        // Check if biometric is available and enabled for re-verification
        const biometricEnabled = await AsyncStorage.getItem('@biometric_enabled');
        const { available } = await rnBiometrics.isSensorAvailable();

        if (available && biometricEnabled === 'true') {
          // Re-verify with biometrics before granting access
          try {
            const { success } = await rnBiometrics.simplePrompt({
              promptMessage: 'Verify your identity',
              cancelButtonText: 'Cancel',
            });

            if (success) {
              setIsAuthenticated(true);
            } else {
              // Biometric failed, require password login
              await AsyncStorage.removeItem(AUTH_KEY);
              setIsAuthenticated(false);
            }
          } catch (error) {
            console.log('Re-verification error:', error);
            // On error, still allow access since they were previously authenticated
            // You can change this behavior based on your security requirements
            setIsAuthenticated(true);
          }
        } else {
          // No biometric re-verification needed, skip login
          setIsAuthenticated(true);
        }
      } else {
        setIsAuthenticated(false);
      }
    } catch (error) {
      console.log('Auth check error:', error);
      setIsAuthenticated(false);
    } finally {
      setIsLoading(false);
    }
  };

  const handleLoginSuccess = () => {
    setIsAuthenticated(true);
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
  };

  if (isLoading) {
    return (
      <View style={styles.container}>
        <ActivityIndicator size="large" color="#007AFF" />
        <Text style={styles.loadingText}>Loading...</Text>
      </View>
    );
  }

  return isAuthenticated ? (
    <HomeScreen onLogout={handleLogout} />
  ) : (
    <LoginScreen onLoginSuccess={handleLoginSuccess} />
  );
};

